// src/pages/KhaiBaoCoSo.js (PHIÊN BẢN KIỂM TRA CUỐI CÙNG - ĐÃ SỬA LỖI IMPORT)
import React from 'react'; // Dòng 1
import { useState, useEffect } from 'react'; // Dòng 2: Tách ra để đảm bảo cú pháp đúng
import { useNavigate } from 'react-router-dom';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';

function KhaiBaoCoSo() {
  console.log("Đang render KhaiBaoCoSo - Phiên bản KIỂM TRA");
  
  const navigate = useNavigate();
  
  const [formData, setFormData] = useState({
    loaiCoSoDangKy: '',
    tenLamSan: '',
  });

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
    }
  }, [navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở (Bản kiểm tra)</h2>
      
      <form className="khai-bao-form">
        <section className="khai-bao-section">
          <h3>Loại cơ sở đăng ký</h3>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở đăng ký:</label>
            <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi (Động vật/Thực vật)</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>
        </section>

        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Thông tin cơ sở gây nuôi</h3>
            <div className="form-group">
              <label htmlFor="tenLamSan">Loài nuôi:</label>
              <select id="tenLamSan" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange}>
                <option value="">-- Chọn loài --</option>
                {Array.isArray(speciesOptions) && speciesOptions.map((species, index) => (
                  <option key={index} value={species.name}>{species.name}</option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label htmlFor="tenKhoaHoc">Tên khoa học (tự động điền):</label>
              <input 
                type="text" 
                id="tenKhoaHoc" 
                name="tenKhoaHoc" 
                value={
                  Array.isArray(speciesOptions) 
                  ? (speciesOptions.find(s => s.name === formData.tenLamSan)?.scientificName || '') 
                  : ''
                } 
                readOnly 
                disabled
              />
            </div>
          </section>
        )}
      </form>
    </div>
  );
}

export default KhaiBaoCoSo;
